function n(e,t){if(e==="admin"&&t==="secret")return{isValid:!0,role:"administrator",lastLogin:new Date};return{isValid:!1,error:"Invalid credentials"}}function i(e){let t=document.getElementById("status");if(e.isValid)t.textContent=`Welcome back, ${e.role}!`,t.style.color="green";else t.textContent="Login failed: "+e.error,t.style.color="red"}(function(){console.log("App initializing...");let e=n("admin","secret");i(e)})();
